1	export interface QuoteItem {
2	  type: string;
3	}
4	
5	export interface QuoteInput {
6	  items: QuoteItem[];
7	  customer: { yearsWithMHPCO: number };
8	  isFollowUp: boolean;
9	}
10	
11	const PROCESSING_FEE = 5;
12	const FIRST_INSURANCE_RATE = 0.1;
13	const BLOCK_OF_3_PREMIUM = 60;
14	
15	const BASE_PREMIUM: Record<string, number> = {
16	  sword: 100,
17	  amulet: 60,
18	  staff: 80,
19	  potion: 40,
20	  rune: 25,
21	  moonstone: 25,
22	};
23	
24	export function quote(input: QuoteInput): number {
25	  let policyBase = 0;
26	
27	  const itemTypeCounts: Record<string, number> = {};
28	  for (const item of input.items) {
29	    itemTypeCounts[item.type] = (itemTypeCounts[item.type] || 0) + 1;
30	  }
31	
32	  for (const [type, count] of Object.entries(itemTypeCounts)) {
33	    if (count === 3) {
34	      policyBase += BLOCK_OF_3_PREMIUM;
35	    } else {
36	      policyBase += count * BASE_PREMIUM[type];
37	    }
38	  }
39	
40	  const policyPremium = policyBase + policyBase * FIRST_INSURANCE_RATE;
41	  return Math.ceil(policyPremium + PROCESSING_FEE);
42	}
43	
